function parseHm(value, fallback) {
  const raw = String(value || fallback || '09:00');
  const [hour, minute] = raw.split(':').map((part) => Number(part || 0));
  return { hour, minute };
}
function moveToWindow(cursor, policy) {
  const start = parseHm(policy.business_hour_start, '09:00');
  const end = parseHm(policy.business_hour_end, '18:00');
  const next = new Date(cursor);
  const isWeekdayOnly = String(policy.holiday_policy || '').toUpperCase() === 'WEEKDAY_BUSINESS_HOURS';
  while (true) {
    const day = next.getDay();
    if (isWeekdayOnly && (day === 0 || day === 6)) {
      next.setDate(next.getDate() + 1);
      next.setHours(start.hour, start.minute, 0, 0);
      continue;
    }
    const currentMinutes = next.getHours() * 60 + next.getMinutes();
    const startMinutes = start.hour * 60 + start.minute;
    const endMinutes = end.hour * 60 + end.minute;
    if (currentMinutes < startMinutes) {
      next.setHours(start.hour, start.minute, 0, 0);
    }
    if (currentMinutes >= endMinutes) {
      next.setDate(next.getDate() + 1);
      next.setHours(start.hour, start.minute, 0, 0);
      continue;
    }
    return next;
  }
}
function addSlaHours(receivedAt, hours, policy) {
  const holidayPolicy = String(policy.holiday_policy || 'CALENDAR_HOURS').toUpperCase();
  const start = new Date(receivedAt);
  if (holidayPolicy === 'CALENDAR_HOURS') {
    return new Date(start.getTime() + hours * 60 * 60 * 1000).toISOString();
  }
  let remainingMinutes = hours * 60;
  let cursor = moveToWindow(start, policy);
  const end = parseHm(policy.business_hour_end, '18:00');
  while (remainingMinutes > 0) {
    const windowEnd = new Date(cursor);
    windowEnd.setHours(end.hour, end.minute, 0, 0);
    const available = Math.max(0, Math.floor((windowEnd.getTime() - cursor.getTime()) / 60000));
    if (available === 0) {
      cursor = moveToWindow(new Date(cursor.getTime() + 24 * 60 * 60 * 1000), policy);
      continue;
    }
    if (remainingMinutes <= available) {
      return new Date(cursor.getTime() + remainingMinutes * 60000).toISOString();
    }
    remainingMinutes -= available;
    cursor = moveToWindow(new Date(windowEnd.getTime() + 60000), policy);
  }
  return cursor.toISOString();
}
function computeStage(receivedAt, dueAt) {
  const received = new Date(receivedAt).getTime();
  const due = new Date(dueAt).getTime();
  const now = Date.now();
  const total = Math.max(1, due - received);
  const elapsed = Math.max(0, now - received);
  const progress = Math.min(999, (elapsed / total) * 100);
